items.decision_tree:
flowchart TD
    Start["Choosing an agent framework"] --> Visual{"Need a visual/no-code builder?"}
    Visual -->|"Yes"| Dify["Use Dify"]
    Visual -->|"No"| Lang{"Primary language?"}
    Lang -->|"TypeScript"| TSFull{"Need a full app framework?"}
    TSFull -->|"Yes"| Mastra["Use Mastra"]
    TSFull -->|"No"| TSCustom["Consider a provider SDK or custom orchestration"]
    Lang -->|"Python"| StateNeed{"Need explicit stateful branching/retries/human-in-the-loop?"}
    StateNeed -->|"Yes"| LangGraph["Use LangGraph"]
    StateNeed -->|"No"| Roles{"Naturally role-based multi-agent team?"}
    Roles -->|"Yes"| CrewAI["Use CrewAI (study MetaGPT for software-company-style patterns)"]
    Roles -->|"No"| Provider{"Provider-native commitment?"}
    Provider -->|"OpenAI"| OpenAISDK["Use OpenAI Agents SDK"]
    Provider -->|"Google/Gemini"| ADK["Use Google ADK"]
    Provider -->|"Microsoft/Azure/.NET"| MAF["Use Microsoft Agent Framework"]
    Provider -->|"Hugging Face/open models"| Smol["Use Smolagents"]
    Provider -->|"Coding-environment agent"| OpenHands["Use OpenHands"]

flowchart TD
    Start["Context approaching the window limit"] --> Old{"Does older content still matter?"}
    Old -->|"No, recency dominates"| Trunc["Truncation / sliding window"]
    Old -->|"Yes"| Fidelity{"Need exact detail or only the gist?"}
    Fidelity -->|"Gist is enough"| Size1{"Large, reusable corpus?"}
    Fidelity -->|"Exact detail required"| Size2{"Large, reusable corpus?"}
    Size1 -->|"No"| Summ["Summarization / compaction"]
    Size1 -->|"Yes"| Ret1["Retrieval offload"]
    Size2 -->|"Yes"| Ret2["Retrieval offload (citable passages)"]
    Size2 -->|"No"| Both["Keep verbatim in-window; combine with light summarization of the rest"]

flowchart TD
    Start["Choosing where to deploy"] --> GPU{"Does this workload need to host model GPUs?"}
    GPU -->|"No, using a hosted model API"| Traffic{"App traffic shape?"}
    Traffic -->|"Small/MVP"| Simple["Railway / Fly.io / FastAPI on a simple host"]
    Traffic -->|"Bursty/serverless-shaped"| Serverless["Modal or another serverless container platform"]
    Traffic -->|"Enterprise cloud commitment"| CloudPlatform{"Existing cloud?"}
    CloudPlatform -->|"AWS"| Bedrock["AWS Bedrock + AWS app hosting"]
    CloudPlatform -->|"Azure"| Azure["Azure AI Studio"]
    CloudPlatform -->|"GCP"| Vertex["Vertex AI"]
    GPU -->|"Yes, self-hosting a model"| Throughput{"Need high-throughput production serving?"}
    Throughput -->|"Yes"| SelfHostServe["vLLM or SGLang on GPU infrastructure"]
    Throughput -->|"No, prototype-scale"| Managed["Hugging Face Inference Endpoints or Replicate"]

flowchart TD
    Start["Choosing an embedding model"] --> Res{"Can document text leave your infrastructure?"}
    Res -->|"No"| OW["Open-weight self-hosted (BGE/GTE/E5-class via TEI)"]
    Res -->|"Yes"| Scale{"Large corpus / frequent re-embedding / sustained volume?"}
    Scale -->|"No"| API["Managed embedding API"]
    Scale -->|"Yes"| OW
    API --> Eval{"Retrieval eval on YOUR corpus shows general models failing?"}
    OW --> Eval
    Eval -->|"No"| Keep["Keep the general model; invest in chunking/hybrid/reranking instead"]
    Eval -->|"Yes, with real relevance pairs available"| FT["Domain-adapt an open-weight model"]

flowchart TD
    Start["Choosing an evaluation approach for a quality dimension"] --> Deterministic{"Is correctness deterministically checkable?"}
    Deterministic -->|"Yes (exact match, schema, threshold)"| Golden["Use golden dataset + deterministic assertions"]
    Deterministic -->|"No, requires judgment"| Volume{"Evaluation volume/frequency?"}
    Volume -->|"Low enough for human review to keep pace"| Human["Use human review directly"]
    Volume -->|"Too high for human review at required frequency"| Judge{"Is an LLM-as-judge rubric already calibrated for this task?"}
    Judge -->|"No"| Calibrate["Calibrate the rubric against a human-labeled sample first"]
    Judge -->|"Yes"| LLMJudge["Use LLM-as-judge for ongoing evaluation, with periodic human audit"]

flowchart TD
    Start["LLM call resilience"] --> Base["Always: bounded retry with backoff + jitter"]
    Base --> Outage{"Must survive a full provider outage?"}
    Outage -->|"No"| Done1["Retries are enough"]
    Outage -->|"Yes"| Alt{"Acceptable second model/provider exists?"}
    Alt -->|"No"| Fail["Fail cleanly; do not fall back to an unacceptable model"]
    Alt -->|"Yes"| Chain["Model/provider fallback chain"]
    Chain --> Many{"Many models + need budgets/observability?"}
    Many -->|"No"| Done2["Keep resilience in the app/library"]
    Many -->|"Yes"| GW["Managed gateway/router centralizes it"]

flowchart TD
    Start["What memory is needed?"] --> Scope{"Does it need to survive past this session?"}
    Scope -->|"No, only within the current chat"| Length{"Will conversation length threaten the context budget?"}
    Length -->|"No"| Window["Use context-window/session state — no extra infrastructure"]
    Length -->|"Yes"| Summary["Use rolling summaries"]
    Scope -->|"Yes, across sessions"| Structure{"Is the information structured (settings, preferences) or fuzzy/narrative?"}
    Structure -->|"Structured"| Relational["Use relational/structured storage"]
    Structure -->|"Fuzzy/narrative"| Validated{"Has cross-session recall been validated as a real product need?"}
    Validated -->|"No, still speculative"| DeferBuild["Defer — instrument usage first, do not build semantic memory speculatively"]
    Validated -->|"Yes"| Volume{"Enough historical volume per user to justify infrastructure?"}
    Volume -->|"No"| Relational
    Volume -->|"Yes"| Semantic["Use vector/semantic memory (DIY vector store, or Mem0/Zep for a managed abstraction)"]

flowchart TD
    Start["Choosing an observability approach"] --> Integration{"How should telemetry enter the system?"}
    Integration -->|"Minimal code change, proxy the API calls"| Proxy["Use a proxy/gateway (Helicone)"]
    Integration -->|"Already OTel-instrumented elsewhere"| OTel["Use an OTel-native tool (Phoenix, OpenLIT, OpenLLMetry)"]
    Integration -->|"Heavy LangChain/LangGraph usage"| Framework["Use LangSmith"]
    Integration -->|"SDK-native, want full lifecycle"| SelfHost{"Self-hosting required or preferred?"}
    SelfHost -->|"Yes"| OSS["Use Langfuse or Opik"]
    SelfHost -->|"No preference"| Need{"Primary need: debugging/tracing, or eval-driven development?"}
    Need -->|"Tracing/debugging"| OSS
    Need -->|"Evaluation-first workflow"| EvalFirst["Use Braintrust or Opik"]

flowchart TD
    Start["Retrieval quality limiting answers?"] --> Recall{"Is the right passage even in the top-k?"}
    Recall -->|"No — recall problem"| FixRecall["Improve first-stage recall (embeddings, hybrid search, chunking) before reranking"]
    Recall -->|"Yes but mis-ranked"| Budget{"Latency and cost budget?"}
    Budget -->|"Tight"| Dense["Stay dense-only; tune retrieval"]
    Budget -->|"Room for one pass"| Cross["Cross-encoder reranker over top-k"]
    Cross --> Enough{"Precision sufficient?"}
    Enough -->|"Yes"| Done["Ship cross-encoder"]
    Enough -->|"No, reasoning-heavy relevance"| LLM["LLM reranker for low-volume high-value queries"]

flowchart TD
    Start["Is a human waiting on the output in real time?"] --> Human{"Human in the loop?"}
    Human -->|"Yes"| Fits1{"Does generation finish within a request timeout?"}
    Fits1 -->|"Yes"| Stream["Streaming (SSE) — hide latency behind time-to-first-token"]
    Fits1 -->|"No — long agentic/multi-step run"| AsyncStream["Async job with streamed progress updates (or async + status UI)"]
    Human -->|"No — machine consumer"| NeedsWhole{"Does the consumer need the complete result before acting?"}
    NeedsWhole -->|"Yes, and it's short"| Sync["Synchronous single response"]
    NeedsWhole -->|"Yes, but it's long / batch"| Async["Asynchronous job + webhook/poll"]
    NeedsWhole -->|"No, can consume incrementally"| StreamM["Streaming (rare for M2M, but valid for pipelines)"]

flowchart TD
    Start["Choosing an LLM serving stack"] --> Data{"Can prompts leave your infrastructure?"}
    Data -->|"No — compliance/residency/IP"| Conc{"Concurrent users?"}
    Data -->|"Yes"| Vol{"Sustained high token volume?"}
    Vol -->|"No — spiky or low volume"| API["Managed API (optionally via LiteLLM gateway)"]
    Vol -->|"Yes — calculate the GPU crossover"| Cap{"Does an open-weight model meet the quality bar?"}
    Cap -->|"No"| API
    Cap -->|"Yes, and team can operate GPUs"| Engine["Self-hosted engine: vLLM / SGLang / TGI"]
    Conc -->|"Single user / edge / dev"| Local["Local runtime: Ollama / llama.cpp"]
    Conc -->|"Many users"| Engine

flowchart TD
    Start["Need structured output"] --> Cost{"What does a malformed response cost?"}
    Cost -->|"A retry — prototype/internal tool"| PP["Prompt-and-parse with retry"]
    Cost -->|"Breaks downstream systems"| Host{"Managed API or self-hosted?"}
    Host -->|"Managed API"| Native["Provider-native structured output via instructor/Pydantic"]
    Host -->|"Self-hosted"| Fmt{"Standard JSON schema, or custom format/hard guarantee?"}
    Fmt -->|"Standard JSON, native mode available"| Native
    Fmt -->|"Custom grammar or must-not-fail"| CD["Grammar-constrained decoding (outlines/guidance, vLLM/SGLang grammars)"]

flowchart TD
    Start["Choosing vector storage"] --> PG{"Already running Postgres in production?"}
    PG -->|"Yes, and scale is under ~10M vectors"| PGV["Use pgvector"]
    PG -->|"No, or scale/features exceed Postgres"| Hosting{"Prefer self-hosted or managed?"}
    Hosting -->|"Managed, minimize ops"| Managed["Use Pinecone, Qdrant Cloud, Weaviate Cloud, or Zilliz"]
    Hosting -->|"Self-hosted"| Scale{"Expected scale?"}
    Scale -->|"Under 1M vectors, prototype"| Embedded["Use Chroma or LanceDB"]
    Scale -->|"1M-100M, production"| Features{"Need advanced hybrid search / multitenancy / filtering?"}
    Features -->|"Yes, performance-critical filtering"| Qdrant["Use Qdrant"]
    Features -->|"Yes, schema-rich hybrid search"| Weaviate["Use Weaviate"]
    Features -->|"No strong feature need"| PGV
    Scale -->|"Over 100M, distributed"| Milvus["Use Milvus / Zilliz"]

flowchart TD
    Start["Choosing a stack scope"] --> Regulated{"Regulated workload or hard compliance requirement?"}
    Regulated -->|"Yes"| Enterprise["Use the Enterprise-Scale Stack"]
    Regulated -->|"No"| MultiTeam{"Multiple teams sharing model access, budgets, or observability?"}
    MultiTeam -->|"Yes"| Enterprise
    MultiTeam -->|"No"| Timeline{"Need to ship in days?"}
    Timeline -->|"Yes"| ProdRAG["Use the Production RAG Stack (or Lean MVP if even faster)"]
    Timeline -->|"No, but need production reliability"| ProdRAG

flowchart TD
    Start["Choosing a stack for a new AI product idea"] --> Validated{"Is product demand already validated with real users?"}
    Validated -->|"No, still validating"| Compliance{"Any compliance/enterprise requirement even at this stage?"}
    Compliance -->|"Yes"| Enterprise["Skip ahead to Enterprise-Scale Stack considerations"]
    Compliance -->|"No"| Lean["Use the Lean MVP Stack"]
    Validated -->|"Yes, real users and traffic"| ProdRAG["Graduate to the Production RAG Stack"]

flowchart TD
    Start["Is there a checkable ground-truth answer?"] --> GT{"Ground truth exists?"}
    GT -->|"Yes (labels, code tests, schema, relevance judgments)"| Ref["Use reference-based / programmatic metrics — cheapest, deterministic, CI-gating"]
    GT -->|"No — quality is subjective/open-ended"| Vol{"Do you need to grade at high volume / continuously?"}
    Vol -->|"Yes"| Judge["LLM-as-judge — but first calibrate against human labels on your task"]
    Vol -->|"No, occasional or high-stakes"| Human["Human evaluation (expert / user feedback)"]
    Judge --> Cal{"Has judge-human agreement been measured?"}
    Cal -->|"No"| Calibrate["Calibrate: sample, human-label, measure agreement, mitigate position/length bias"]
    Cal -->|"Yes, agreement acceptable"| Compose["Run judge at scale + periodic human audit + reference metrics where applicable"]
    Human --> Compose

flowchart TD
    Start["Choosing local-first vs cloud API"] --> Residency{"Data cannot leave local environment?"}
    Residency -->|"Yes"| Local["Use the Local-First Stack"]
    Residency -->|"No"| Offline{"Must work offline / field deployment?"}
    Offline -->|"Yes"| Local
    Offline -->|"No"| Quality{"Does the task need frontier-model quality beyond current open-weight local models?"}
    Quality -->|"Yes"| Cloud["Use a cloud API stack (Lean MVP or Production RAG)"]
    Quality -->|"No"| CostSensitive{"Cost-sensitive at high, steady usage volume?"}
    CostSensitive -->|"Yes"| Local
    CostSensitive -->|"No"| Cloud

flowchart TD
    Start["Choosing single-agent vs multi-agent"] --> Stages{"Does the task have genuinely distinct stages (plan/research/execute/review)?"}
    Stages -->|"No, single bounded loop"| SingleAgent["Use a single-agent loop (see Simple ReAct Agent / Multi-Tool Agent build examples)"]
    Stages -->|"Yes"| Approval{"Needs human approval/rollback before high-impact actions?"}
    Approval -->|"Yes"| MultiAgent["Use the Multi-Agent System Stack"]
    Approval -->|"No, but still multi-stage"| Complexity{"Is the multi-stage structure complex enough to warrant separate roles/permissions?"}
    Complexity -->|"Yes"| MultiAgent
    Complexity -->|"No"| SingleAgent

flowchart TD
    Start["Choosing a RAG stack maturity level"] --> Users{"Real users depending on answer quality?"}
    Users -->|"No, still prototyping"| Lean["Use the Lean MVP Stack"]
    Users -->|"Yes"| Corpus{"Is the document corpus stable?"}
    Corpus -->|"No, still changing significantly"| StabilizeFirst["Stabilize the corpus before investing in production ingestion -- stay on a lighter setup meanwhile"]
    Corpus -->|"Yes"| Capacity{"Team has capacity to operate evals/tracing/ingestion ops?"}
    Capacity -->|"No"| BuildCapacity["Build that capacity before adopting the full stack, or scope down to what can actually be operated"]
    Capacity -->|"Yes"| ProdRAG["Use the Production RAG Stack"]

flowchart TD
    Start["What is actually failing?"] --> Problem{"Missing/private/fresh facts, or wrong behavior/format?"}
    Problem -->|"Missing or changing facts"| RAGPath{"How often does the knowledge change?"}
    RAGPath -->|"Daily/weekly/real-time"| RAGStrong["Use RAG — fine-tuning cannot keep pace"]
    RAGPath -->|"Static or monthly+"| RAGEval{"Is retrieval quality good enough on a real eval set?"}
    RAGEval -->|"Yes"| RAGOk["Use RAG"]
    RAGEval -->|"No, and won't be soon"| Improve["Improve parsing/chunking/reranking before considering fine-tuning as a workaround"]
    Problem -->|"Wrong format, tone, or narrow task behavior"| DataCheck{"Do you have 200+ labeled examples of the correct behavior?"}
    DataCheck -->|"No"| PromptFirst["Try prompting + few-shot examples first (recovers ~70-80% of fine-tuning benefit at zero training cost)"]
    DataCheck -->|"Yes, 200-2000"| FTNarrow["Fine-tune (LoRA) for style/format/narrow-task adaptation"]
    DataCheck -->|"Yes, 5000+"| FTBroad["Fine-tune (LoRA/QLoRA) for broader instruction or domain adaptation"]
    Problem -->|"Both knowledge and behavior are wrong"| Hybrid["Use RAG + fine-tuning together — see Approach Deep-Dives"]

flowchart TD
    Start["Choosing a research platform vs a product stack"] --> Goal{"Primary goal: systematic comparison of variants, or shipping a product?"}
    Goal -->|"Systematic comparison / research"| Discipline{"Team has capacity to maintain versioned datasets and eval harnesses?"}
    Discipline -->|"Yes"| Research["Use the Research Platform Stack"]
    Discipline -->|"No"| BuildDiscipline["Build that capacity first, or the stack's value won't be realized regardless of tooling"]
    Goal -->|"Shipping a product"| Uptime{"Strict production uptime is the primary goal?"}
    Uptime -->|"Yes"| ProductStack["Use a Product Stack (Lean MVP or Production RAG)"]
    Uptime -->|"No, still early"| ProductStack

flowchart TD
    Start["Does data have a hard residency / privacy constraint?"] --> Gov{"Must inference stay in your environment?"}
    Gov -->|"Yes, and no acceptable private/in-region provider"| Self["Self-host open weights (constraint overrides cost)"]
    Gov -->|"No"| Quality{"Does only a frontier proprietary model clear your quality bar?"}
    Quality -->|"Yes"| API["Hosted API — it's the only path to that model"]
    Quality -->|"No, open weights are good enough"| Volume{"Is volume high AND sustained (GPUs would stay busy)?"}
    Volume -->|"No — low or spiky"| APILow["Hosted API — pay per token, don't buy idle GPUs"]
    Volume -->|"Yes"| Ops{"Do you have inference/SRE capability for a GPU service?"}
    Ops -->|"No"| APIorHosted["Hosted API (or hosted open-weights) until you build the capability"]
    Ops -->|"Yes"| SelfHost["Self-host open weights — amortized cost + control win here"]

flowchart TD
    Start["Designing an agent system"] --> Fit{"Does the working set fit one context window (with summarization/retrieval)?"}
    Fit -->|"Yes"| Par{"Are there independent subtasks where parallel wall-clock time matters?"}
    Fit -->|"No"| Orch["Orchestrator + subagents: isolate context per subtask"]
    Par -->|"No"| Single["Single agent with tools — the default"]
    Par -->|"Yes"| Worth{"Is the wall-clock/isolation win worth a multiple of the token cost?"}
    Worth -->|"No"| Single
    Worth -->|"Yes"| Orch
    Single --> Verify{"Would a separate verifier against an objective check catch real errors?"}
    Verify -->|"Yes"| Peer["Add a critic/verifier role with defined termination"]
    Verify -->|"No"| Single
